using Microsoft.ML.Data;

namespace TicketClassifier.Models;

public class TicketInput
{
    [LoadColumn(0)]
    public string Subject { get; set; } = string.Empty;

    [LoadColumn(1)]
    public string Description { get; set; } = string.Empty;

    [LoadColumn(2)]
    public float Priority { get; set; }

    [LoadColumn(3)]
    public string Category { get; set; } = string.Empty;
}

using Microsoft.ML.Data;

namespace TicketClassifier.Models;

public class TicketPrediction
{
    [ColumnName("PredictedLabel")]
    public string PredictedLabel { get; set; } = string.Empty;

    [ColumnName("Score")]
    public float[] Score { get; set; } = [];
}

namespace TicketClassifier.Models;

public class ClassifyRequest
{
    public string Subject { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
    public int Priority { get; set; }
}

namespace TicketClassifier.Models;

public class ClassifyResponse
{
    public string Category { get; set; } = string.Empty;
    public float Confidence { get; set; }
    public Dictionary<string, float> Scores { get; set; } = new();
}

using Microsoft.ML;
using TicketClassifier.Models;

namespace TicketClassifier.Services;

public class ModelTrainerService : IHostedService
{
    private readonly ILogger<ModelTrainerService> _logger;
    private readonly IWebHostEnvironment _env;

    public ModelTrainerService(ILogger<ModelTrainerService> logger, IWebHostEnvironment env)
    {
        _logger = logger;
        _env = env;
    }

    public Task StartAsync(CancellationToken cancellationToken)
    {
        var mlContext = new MLContext(seed: 42);

        var dataPath = Path.Combine(_env.ContentRootPath, "Data", "tickets.csv");
        var modelPath = Path.Combine(_env.ContentRootPath, "Data", "TicketModel.zip");

        var modelDir = Path.GetDirectoryName(modelPath)!;
        Directory.CreateDirectory(modelDir);

        _logger.LogInformation("Loading training data from {DataPath}", dataPath);

        var data = mlContext.Data.LoadFromTextFile<TicketInput>(
            dataPath,
            hasHeader: true,
            separatorChar: ',',
            allowQuoting: true);

        var split = mlContext.Data.TrainTestSplit(data, testFraction: 0.2, seed: 42);

        var pipeline = mlContext.Transforms.Conversion.MapValueToKey("Label", nameof(TicketInput.Category))
            .Append(mlContext.Transforms.Text.FeaturizeText("SubjectFeaturized", nameof(TicketInput.Subject)))
            .Append(mlContext.Transforms.Text.FeaturizeText("DescriptionFeaturized", nameof(TicketInput.Description)))
            .Append(mlContext.Transforms.Concatenate("Features", "SubjectFeaturized", "DescriptionFeaturized", nameof(TicketInput.Priority)))
            .Append(mlContext.MulticlassClassification.Trainers.SdcaMaximumEntropy("Label", "Features"))
            .Append(mlContext.Transforms.Conversion.MapKeyToValue("PredictedLabel"));

        _logger.LogInformation("Training model...");
        var model = pipeline.Fit(split.TrainSet);

        var predictions = model.Transform(split.TestSet);
        var metrics = mlContext.MulticlassClassification.Evaluate(predictions, labelColumnName: "Label");

        _logger.LogInformation("Model evaluation metrics:");
        _logger.LogInformation("  MicroAccuracy:  {MicroAccuracy:F4}", metrics.MicroAccuracy);
        _logger.LogInformation("  MacroAccuracy:  {MacroAccuracy:F4}", metrics.MacroAccuracy);
        _logger.LogInformation("  LogLoss:        {LogLoss:F4}", metrics.LogLoss);

        mlContext.Model.Save(model, data.Schema, modelPath);
        _logger.LogInformation("Model saved to {ModelPath}", modelPath);

        return Task.CompletedTask;
    }

    public Task StopAsync(CancellationToken cancellationToken) => Task.CompletedTask;
}

using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.ML;
using TicketClassifier.Models;

namespace TicketClassifier.Controllers;

[ApiController]
[Route("api/tickets")]
public class TicketController : ControllerBase
{
    private readonly PredictionEnginePool<TicketInput, TicketPrediction> _predictionPool;

    public TicketController(PredictionEnginePool<TicketInput, TicketPrediction> predictionPool)
    {
        _predictionPool = predictionPool;
    }

    [HttpPost("classify")]
    public ActionResult<ClassifyResponse> Classify([FromBody] ClassifyRequest request)
    {
        var input = new TicketInput
        {
            Subject = request.Subject,
            Description = request.Description,
            Priority = request.Priority
        };

        var prediction = _predictionPool.Predict(input);

        var labels = new[] { "Billing", "General", "Technical" };
        var scores = new Dictionary<string, float>();
        for (var i = 0; i < labels.Length && i < prediction.Score.Length; i++)
        {
            scores[labels[i].ToLowerInvariant()] = prediction.Score[i];
        }

        var confidence = prediction.Score.Length > 0 ? prediction.Score.Max() : 0f;

        return Ok(new ClassifyResponse
        {
            Category = prediction.PredictedLabel,
            Confidence = confidence,
            Scores = scores
        });
    }
}

