using Microsoft.Extensions.ML;
using TicketClassifier.Models;
using TicketClassifier.Services;

var builder = WebApplication.CreateBuilder(args);
builder.Services.AddControllers();

builder.Services.AddHostedService<ModelTrainerService>();

var modelPath = Path.Combine(builder.Environment.ContentRootPath, "Data", "TicketModel.zip");
builder.Services.AddPredictionEnginePool<TicketInput, TicketPrediction>()
    .FromFile(filePath: modelPath, watchForChanges: true);

var app = builder.Build();
app.MapControllers();
app.Run();

