using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.ML;
using TicketClassifier.Models;
using TicketClassifier.Services;

namespace TicketClassifier.Controllers;

[ApiController]
[Route("api/tickets")]
public class TicketController : ControllerBase
{
    private readonly PredictionEnginePool<TicketInput, TicketPrediction> _predictionPool;
    private readonly ModelMetadata _metadata;

    public TicketController(PredictionEnginePool<TicketInput, TicketPrediction> predictionPool, ModelMetadata metadata)
    {
        _predictionPool = predictionPool;
        _metadata = metadata;
    }

    [HttpPost("classify")]
    public ActionResult<ClassifyResponse> Classify([FromBody] ClassifyRequest request)
    {
        var input = new TicketInput
        {
            Subject = request.Subject,
            Description = request.Description,
            Priority = request.Priority
        };

        var prediction = _predictionPool.Predict(input);

        var scores = new Dictionary<string, float>();
        for (var i = 0; i < _metadata.Labels.Length && i < prediction.Score.Length; i++)
        {
            scores[_metadata.Labels[i].ToLowerInvariant()] = prediction.Score[i];
        }

        var confidence = prediction.Score.Length > 0 ? prediction.Score.Max() : 0f;

        return Ok(new ClassifyResponse
        {
            Category = prediction.PredictedLabel,
            Confidence = confidence,
            Scores = scores
        });
    }
}

